module RefModule(clk, rst, load, D, SI, Q);
    input clk, rst, load, SI;
    input [7:0] D;
    output reg [7:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            Q <= 8'b00000000;
        else if (load)
            Q <= D;
        else
            Q <= {Q[6:0], SI};
    end
endmodule
